-- ── CO-DOMINANT MORPHS ───────────────────────────────────────
-- These have a visual het form AND a super/homozygous form
INSERT OR IGNORE INTO morphs (id, species_id, name, gene_symbol, category, inheritance_type, super_form_name, has_health_concern, health_concern_desc, description, also_known_as, discovered_year, sort_order) VALUES

-- Foundational co-doms
('bp_pastel',        'ball_python', 'Pastel',           'pst',  'Co-dominant', 'co_dominant', 'Super Pastel',     0, NULL, 'Brightens yellow pigment and reduces pattern. One of the most common and versatile morphs. Super pastel is near-white with yellow blush.', NULL, 1997, 10),
('bp_spider',        'ball_python', 'Spider',           'sp',   'Co-dominant', 'co_dominant', 'Super Spider',     1, 'Neurological wobble - head tremor and balance issues. Severity varies. Super spider shows severe wobble. Controversial morph.', 'The most visually striking basic morph. Thin, web-like pattern with white belly. IMPORTANT: Carries neurological wobble. Super form is not recommended.', 'Woma Pattern (incorrect)', 1999, 20),
('bp_lesser',        'ball_python', 'Lesser',           'les',  'Co-dominant', 'co_dominant', 'Butter',           0, NULL, 'Brightens and cleans the pattern. Super form (Butter) is a pale yellow animal. Essential component in the BEL complex.', 'Lesser Platinum', 2001, 30),
('bp_mojave',        'ball_python', 'Mojave',           'moj',  'Co-dominant', 'co_dominant', 'Super Mojave',     0, NULL, 'Reduces and brightens pattern. Clean sides. Super Mojave is a white animal with blue/grey eyes - part of the BEL complex.', NULL, 2000, 40),
('bp_phantom',       'ball_python', 'Phantom',          'phn',  'Co-dominant', 'co_dominant', 'Super Phantom',    0, NULL, 'Reduces pattern and brightens yellows. Super Phantom is part of the BEL complex producing white animals.', NULL, 2005, 50),
('bp_mystic',        'ball_python', 'Mystic',           'mys',  'Co-dominant', 'co_dominant', 'Super Mystic',     0, NULL, 'Similar to Phantom. Part of the BEL complex. Super Mystic produces a white animal with dark eyes.', 'Mistique', 2006, 55),
('bp_butter',        'ball_python', 'Butter',           'but2', 'Co-dominant', 'co_dominant', 'Super Butter',     0, NULL, 'The super form of Lesser. Pale yellow, clean animal. Also used to describe the super form of some combos.', NULL, 2001, 58),
('bp_het_russo',     'ball_python', 'Het Russo (Dominant line)', 'hru','Co-dominant','co_dominant','Super Russo', 0, NULL, 'Pattern reducing co-dominant. Different from the recessive Russo gene.', NULL, 2007, 60),
('bp_yellow_belly',  'ball_python', 'Yellow Belly',     'yb',   'Co-dominant', 'co_dominant', 'Ivory',            0, NULL, 'Subtle in isolation - slightly cleaner sides and yellow belly. Super Yellow Belly (Ivory) is a stunning white/cream animal with yellow sides.', 'YB', 2000, 70),
('bp_gravel',        'ball_python', 'Gravel',           'grv',  'Co-dominant', 'co_dominant', 'Super Gravel',     0, NULL, 'Reduces pattern and alters colouration. Allelic to Yellow Belly. Super form is similar to Ivory.', NULL, 2009, 75),
