('bp_pinstripe',     'ball_python', 'Pinstripe',        'pin',  'Co-dominant', 'co_dominant', 'Super Pinstripe',  0, NULL, 'Reduces lateral pattern to a thin pinstripe. Cleaner dorsal. Super Pinstripe is nearly patternless with a dorsal line.', 'Pin', 2001, 100),
('bp_woma',          'ball_python', 'Woma',             'wom',  'Co-dominant', 'co_dominant', 'Super Woma',       0, NULL, 'Banded pattern with faded sides. Resembles Woma python patterning. Super Woma has extreme pattern reduction.', 'Collision', 2001, 110),
