-- ── DOMINANT MORPHS ───────────────────────────────────────────
('bp_spider_dom',    'ball_python', 'Spider',           'sp2',  'Dominant', 'dominant', NULL, 1, 'Neurological wobble - head tremor and balance issues. The primary Spider gene is dominant. Severity varies individual to individual. Super Spider (homozygous) shows severe, often life-limiting wobble.', 'Webbing pattern, reduced lateral markings, white belly, variable banding. The original and most common Spider. Dominant - one copy produces the visual.', NULL, 1999, 10),
('bp_pinstripe_dom', 'ball_python', 'Pinstripe',        'pin2', 'Dominant', 'dominant', NULL, 0, NULL, 'Dominant pinstripe (some lines). Most pinstripes are co-dominant with a super form.', NULL, 2001, 20),
('bp_disco',         'ball_python', 'Disco',            'dis',  'Dominant', 'dominant', NULL, 0, NULL, 'Fragmented, disco-ball-like pattern. Dominant - one copy produces visual.', NULL, 2010, 30),
('bp_scaleless',     'ball_python', 'Scaleless',        'scl',  'Dominant', 'dominant', NULL, 0, NULL, 'Completely scaleless body and head. Smooth, tactile appearance. Dominant expression but complex genetics.', NULL, 2013, 40);
